from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetTasksNode(BaseNode):
    name = "Prism: Get Tasks"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="fx")
        self.add_output("tasks", "list")
        self.add_output("count", "int")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get("entity") or {}
        dept = inputs.get("department") or ""
        if core is None:
            self.log_error("No PrismCore found.")
            return {"tasks": [], "count": 0}
        tasks = []
        ents = core.entities
        # try every plausible method signature
        attempts = [
            ("getTaskNames",   lambda: ents.getTaskNames(entity, dept)),
            ("getTaskNames(e)", lambda: ents.getTaskNames(entity)),
            ("getTasks",        lambda: ents.getTasks(entity, dept)),
            ("getTasks(e)",     lambda: ents.getTasks(entity)),
            ("getStepNames",    lambda: ents.getStepNames(entity, dept)),
            ("getSteps",        lambda: ents.getSteps(entity, dept)),
        ]
        for label, fn in attempts:
            if not hasattr(ents, label.split("(")[0]):
                continue
            try:
                result = fn()
                if result is not None:
                    tasks = list(result)
                    self.log_info(f"Used {label} -> {len(tasks)} task(s)")
                    break
            except Exception as e:
                self.log_info(f"{label} failed: {e}")
        if not tasks:
            # fallback: derive task names from scene file paths
            try:
                files = ents.getScenefiles(entity, department=dept) or []
                seen = set()
                for sf in files:
                    task = sf.get("task", "") if isinstance(sf, dict) else ""
                    if task and task not in seen:
                        seen.add(task)
                        tasks.append(task)
                if tasks:
                    self.log_info(f"Derived {len(tasks)} task(s) from scene files")
            except Exception as e:
                self.log_error(f"Scene file fallback failed: {e}")
        if not tasks:
            avail = [m for m in dir(ents) if not m.startswith("_") and "task" in m.lower()]
            self.log_error(f"No task method found. task-related methods on entities: {avail}")
        return {"tasks": tasks, "count": len(tasks)}

def register_node():
    return PrismGetTasksNode
